// ── Helper exports ──────────────────────────────────────────────────────────

/** All unique industry tags across the portfolio */
export const allIndustries: string[] = [
  ...new Set(projects.flatMap((p) => p.targetIndustries)),
];

/** All unique project types */
export const allTypes: string[] = [
  ...new Set(projects.map((p) => p.type.trim())),
];

/** Lookup a project by its id */
export function getProjectById(id: number): Project | undefined {
  return projects.find((p) => p.id === id);
}

/** Filter projects by partial industry match */
export function filterByIndustry(industry: string): Project[] {
  const q = industry.toLowerCase();
  return projects.filter((p) =>
    p.industry.toLowerCase().includes(q) ||
    p.targetIndustries.some((i) => i.toLowerCase().includes(q))
  );
}

/** Filter projects by tag */
export function filterByTag(tag: string): Project[] {
  const q = tag.toLowerCase();
  return projects.filter((p) => p.tags.some((t) => t.toLowerCase().includes(q)));
}

/** Filter projects by platform type (Web / Mobile / etc.) */
export function filterByType(type: string): Project[] {
  const q = type.toLowerCase();
  return projects.filter((p) => p.type.toLowerCase().includes(q));
}